import React, { useId } from 'react';
import { Card, CardContent, Box, Typography, Stack } from '@mui/material';
import { BarChart } from '@mui/x-charts';
import response from './response.json';

interface ApiStats {
  requestCount: number;
  averageLatency: number;
  errorRate: number;
}

interface ErrorRateByDay {
  day: string;
  errorRate: number;
}

interface ApiUsageData {
  apiStats: ApiStats;
  errorRateByDay: ErrorRateByDay[];
}

export default function Widget() {
  const apiUsageData = response.data as ApiUsageData;
  const { apiStats, errorRateByDay } = apiUsageData;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 350, maxWidth: 450, bgcolor: '#263238' }} elevation={2}>
      <CardContent sx={{ p: 3 }}>
        <Stack spacing={2.5}>
          <Box>
            <Typography variant="h6" color="#FF5722" fontWeight={600}>
              API Monitor
            </Typography>
            <Typography variant="body2" color="text.secondary">
              Requests: {apiStats.requestCount}
            </Typography>
            <Typography variant="body2" color="text.secondary">
              Avg Latency: {apiStats.averageLatency} ms
            </Typography>
            <Typography variant="body2" color="text.secondary">
              Error Rate: {apiStats.errorRate}%
            </Typography>
          </Box>

          <BarChart
            height={140}
            series={[
              {
                data: errorRateByDay.map(day => day.errorRate),
                color: '#FF5722',
              },
            ]}
            xAxis={[
              {
                data: errorRateByDay.map(day => day.day),
                scaleType: 'band',
                tickLabelStyle: {
                  fontSize: 11,
                  fill: '#B0BEC5',
                },
              },
            ]}
            margin={{ top: 10, bottom: 30, left: 40, right: 10 }}
            sx={{
              '& .MuiBarElement-root': {
                rx: 4,
              },
            }}
          />
        </Stack>
      </CardContent>
    </Card>
  );
}
